#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int shortestCommonSupersequence(string X, string Y) {
        int m = X.size(), n = Y.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1));
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (X[i - 1] == Y[j - 1]) {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                } else {
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
                }
            }
        }
        int lcs_length = dp[m][n];
        return m + n - lcs_length;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    if (!(cin >> t)) return 0;
    for (int _ = 0; _ < t; _++) {
        string X, Y;
        cin >> X >> Y;
        Solution sol;
        int ans = sol.shortestCommonSupersequence(X, Y);
        cout << ans << "\n";
    }
    return 0;
}
